#include <stdio.h>
int main() {
    char s[100], t[100];
    scanf("%s %s", s, t);
    int m1[256] = {0}, m2[256] = {0};
    int n = 0;
    while (s[n] != '\0' && t[n] != '\0') {
        if (m1[s[n]] != m2[t[n]]) return 0;
        m1[s[n]] = n + 1;
        m2[t[n]] = n + 1;
        n++;
    }
    if (s[n] == '\0' && t[n] == '\0') printf("true");
    else printf("false");
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    bool isomorphicString(string s, string t) {
        int m1[256] = {0}, m2[256] = {0};
        int n = s.size();
        for (int i = 0; i < n; ++i) {
            if (m1[s[i]] != m2[t[i]]) return false;
            m1[s[i]] = i + 1;
            m2[t[i]] = i + 1;
        }
        return true;
    }
};

